SELECT PLACE_ID , PLACE_TYPE , NAME , ADDRESS , IMAGE_URL , VIEW_COUNT , LATITUDE , LONGITUDE , placeRegDate , avg_rating , review_count FROM ( SELECT ROW_NUMBER() OVER(ORDER BY f.CREATED_AT DESC) AS rn , p.PLACE_ID , p.PLACE_TYPE , p.NAME , p.ADDRESS , p.IMAGE_URL , p.VIEW_COUNT , p.LATITUDE , p.LONGITUDE , p.CREATED_AT AS placeRegDate , (SELECT NVL(ROUND(AVG(rv.RATING), 1), 0) FROM REVIEW rv WHERE rv.PLACE_ID = p.PLACE_ID AND rv.STATUS = 'DISPLAY') AS avg_rating , (SELECT COUNT(rv.REVIEW_ID) FROM REVIEW rv WHERE rv.PLACE_ID = p.PLACE_ID AND rv.STATUS = 'DISPLAY') AS review_count FROM PLACE p JOIN FAVORITE f ON p.PLACE_ID = f.PLACE_ID WHERE f.USER_ID = #{user_id}
AND p.PLACE_TYPE = #{category}
) WHERE rn BETWEEN #{start} AND #{end}

SELECT COUNT(*)
FROM FAVORITE f
JOIN PLACE p
  ON f.PLACE_ID = p.PLACE_ID
WHERE f.USER_ID = #{user_id}

    AND p.PLACE_TYPE = #{category}

SELECT * FROM ( SELECT ROW_NUMBER() OVER(ORDER BY created_at DESC) as rn, INQUIRY_ID, USER_ID, CATEGORY, TITLE, STATUS, CREATED_AT, ANSWERED_AT FROM INQUIRY WHERE USER_ID = #{user_id}
AND STATUS = #{status}
) WHERE rn BETWEEN #{start} AND #{end}

